// Solution
function validatePortCollisions(services) {
  let collisions = new Set();
  for (let service of services) {
    for (let port of service.ports) {
      collisions.add(port.containerPort);
    }
  }
  for (let service of services) {
    let serviceCollisions = new Set();
    for (let port of service.ports) {
      if (collisions.has(port.containerPort)) {
        serviceCollisions.add(port.containerPort);
      }
    }
    if (serviceCollisions.size > 1) {
      collisions.add(service.name);
    }
  }
  return Array.from(collisions).filter(x => services.find(s => s.name === x));
}

