class Solution:
  def validatePortCollisions(self, services):
    collisions = set()
    for service in services:
      for port in service.ports:
        collisions.add(port.containerPort)
    for service in services:
      service_collisions = set()
      for port in service.ports:
        if port.containerPort in collisions:
          service_collisions.add(port.containerPort)
      if len(service_collisions) > 1:
        collisions.add(service.name)
    return [name for name in collisions if services.find(lambda s: s.name == name)]
